static int qmp_pcie_init(struct phy *phy)
{
	struct qmp_pcie *qmp = phy_get_drvdata(phy);
	const struct qmp_phy_cfg *cfg = qmp->cfg;
	void __iomem *pcs = qmp->pcs;
	int ret;

	/*
	 * We can skip PHY initialization if all of the following conditions
	 * are met:
	 *  1. The PHY supports the nocsr_reset that preserves the PHY config.
	 *  2. The PHY was started (and not powered down again) by the
	 *     bootloader, with all of the expected bits set correctly.
	 * In this case, we can continue without having the init sequence
	 * defined in the driver.
	 */
	qmp->skip_init = qmp->nocsr_reset &&
		qphy_checkbits(pcs, cfg->regs[QPHY_START_CTRL], SERDES_START | PCS_START) &&
		qphy_checkbits(pcs, cfg->regs[QPHY_PCS_POWER_DOWN_CONTROL], cfg->pwrdn_ctrl);

	if (!qmp->skip_init && !cfg->tbls.serdes_num) {
		dev_err(qmp->dev, "Init sequence not available\n");
		return -ENODATA;
	}

	ret = regulator_bulk_enable(cfg->num_vregs, qmp->vregs);
	if (ret) {
		dev_err(qmp->dev, "failed to enable regulators, err=%d\n", ret);
		return ret;
	}

	/*
	 * Toggle BCR reset for PHY that doesn't support no_csr reset or has not
	 * been initialized.
	 */
	if (!qmp->skip_init) {
		ret = reset_control_bulk_assert(cfg->num_resets, qmp->resets);
		if (ret) {
			dev_err(qmp->dev, "reset assert failed\n");
			goto err_disable_regulators;
		}
	}

	ret = reset_control_assert(qmp->nocsr_reset);
	if (ret) {
		dev_err(qmp->dev, "no-csr reset assert failed\n");
		goto err_assert_reset;
	}

	usleep_range(200, 300);

	if (!qmp->skip_init) {
		ret = reset_control_bulk_deassert(cfg->num_resets, qmp->resets);
		if (ret) {
			dev_err(qmp->dev, "reset deassert failed\n");
			goto err_assert_reset;
		}
	}

	ret = clk_bulk_prepare_enable(ARRAY_SIZE(qmp_pciephy_clk_l), qmp->clks);
	if (ret)
		goto err_assert_reset;

	return 0;

err_assert_reset:
	if (!qmp->skip_init)
		reset_control_bulk_assert(cfg->num_resets, qmp->resets);
err_disable_regulators:
	regulator_bulk_disable(cfg->num_vregs, qmp->vregs);

	return ret;
}

static int qmp_pcie_exit(struct phy *phy)
{
	struct qmp_pcie *qmp = phy_get_drvdata(phy);
	const struct qmp_phy_cfg *cfg = qmp->cfg;

	if (qmp->nocsr_reset)
		reset_control_assert(qmp->nocsr_reset);
	else
		reset_control_bulk_assert(cfg->num_resets, qmp->resets);

	clk_bulk_disable_unprepare(ARRAY_SIZE(qmp_pciephy_clk_l), qmp->clks);

	regulator_bulk_disable(cfg->num_vregs, qmp->vregs);

	return 0;
}

static int qmp_pcie_power_on(struct phy *phy)
{
	struct qmp_pcie *qmp = phy_get_drvdata(phy);
	const struct qmp_phy_cfg *cfg = qmp->cfg;
	const struct qmp_phy_cfg_tbls *mode_tbls;
	void __iomem *pcs = qmp->pcs;
	void __iomem *status;
	unsigned int mask, val;
	int ret;

	/*
	 * Write CSR register for PHY that doesn't support no_csr reset or has not
	 * been initialized.
